const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');
const { body, validationResult } = require('express-validator');
const app = express();
const client = new Client({ node: 'http://localhost:9200' });

app.use(bodyParser.json());

const allowedIndices = ['index1', 'index2', 'index3']; // Define your allowed indices

app.post('/search/:index', 
  body('query').isObject(), 
  (req, res) => {
    const index = req.params.index;

    // Validate index
    if (!allowedIndices.includes(index)) {
      return res.status(403).json({ error: 'Forbidden index' });
    }

    // Validate request body
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // Execute search
    client.search({ index, body: req.body.query })
      .then(result => res.json(result.body))
      .catch(err => res.status(500).json({ error: err.message }));
  }
);

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});